UPDATE RETURN_REQUEST
SET status='REJECTED',
    reject_reason=#{rejectReason}
WHERE return_group_id = #{returnGroupId}
  AND status = 'REQUESTED'

UPDATE inventory_lot
SET current_qty=current_qty + #{returnQty}
WHERE inventory_lot_id = #{inventoryLotId}

mapper.select:
SELECT COUNT(*) FROM return_request rr


        AND rr.status=#{status}


        AND rr.so_id=#{salesOrderId}

SELECT MIN(rr.return_id) as returnId, rr.so_id as salesOrderId, sd.shipment_detail_id as shipmentDetailId, cu.customer_name as customerName, rr.return_group_id as returnGroupId, rr.customer_id as customerId, pr.product_name as productName, il.lot_no as lotNo, rr.reason as reason, rr.status as status, MIN(rr.created_at) as createdAt, rr.created_by as createdBy, em1.emp_name as createdByName, MAX(rr.approved_at) as approvedAt, rr.approved_by as approvedBy, em2.emp_name as approvedByName, MAX(rr.completed_at) as completedAt, MAX(rr.reject_reason) as rejectReason, COUNT(*) as itemCount, NVL(SUM(rr.return_qty),0) as returnQty FROM return_request rr JOIN sales_order so ON so.so_id=rr.so_id LEFT JOIN customer cu ON cu.customer_id = rr.customer_id LEFT JOIN employee em1 ON em1.emp_id=rr.created_by LEFT JOIN employee em2 ON em2.emp_id=rr.approved_by LEFT JOIN product pr ON pr.product_id=rr.product_id LEFT JOIN shipment_detail sd ON sd.shipment_detail_id=rr.shipment_detail_id LEFT JOIN inventory_lot il ON il.inventory_lot_id=sd.inventory_lot_id
AND rr.status=#{status}
AND rr.so_id=#{salesOrderId}
AND rr.return_group_id=#{returnGroupId}
GROUP BY rr.so_id, cu.customer_name, rr.return_group_id, rr.customer_id, sd.shipment_detail_id, rr.product_id, pr.product_name, sd.inventory_lot_id, il.lot_no, rr.status, rr.reason, rr.created_by, rr.approved_by, em1.emp_name, em2.emp_name ORDER BY MIN(rr.created_at) DESC, rr.return_group_id DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT rr.return_group_id, rr.so_id as salesOrderId, rr.customer_id, cu.customer_name, COUNT(rr.return_id) as itemCount, SUM(rr.return_qty) as totalReturnQty, MIN(pr.product_name) || CASE WHEN COUNT(rr.return_id)>1 THEN ' 외' || (COUNT(rr.return_id)-1) || ' 개' ELSE '' END AS productSummary, MIN(rr.reason) as reason, rr.status as status, rr.created_by as createdBy, em1.emp_name as createdByName, MIN(rr.created_at) as createdAt, rr.approved_by as approvedBy, em2.emp_name as approvedName, MIN(rr.approved_at) as approvedAt, MAX(rr.completed_at) as completedAt, MAX(rr.reject_reason) as rejectReason FROM return_request rr LEFT JOIN customer cu ON cu.customer_id=rr.customer_id LEFT JOIN product pr on pr.product_id=rr.product_id LEFT JOIN employee em1 ON em1.emp_id=rr.created_by LEFT JOIN employee em2 ON em2.emp_id=rr.approved_by
AND rr.status=#{status}
AND rr.so_id=#{salesOrderId}
GROUP BY rr.return_group_id, rr.so_id, rr.customer_id, cu.customer_name, rr.status, rr.created_by, em1.emp_name, rr.approved_by, em2.emp_name ORDER BY rr.return_group_id DESC OFFSET #{offset} ROWS FETCH NEXT #{size} ROWS ONLY

SELECT COUNT(DISTINCT rr.return_group_id) FROM return_request rr


        AND rr.status=#{status}


        AND rr.so_id=#{salesOrderId}
